    51	func (a *ServiceAction) Execute(input *velero.RestoreItemActionExecuteInput) (*velero.RestoreItemActionExecuteOutput, error) {
    52		service := new(corev1api.Service)
    53		if err := runtime.DefaultUnstructuredConverter.FromUnstructured(input.Item.UnstructuredContent(), service); err != nil {
    54			return nil, errors.WithStack(err)
    55		}
    56	
    57		if service.Spec.ClusterIP != "None" {
    58			service.Spec.ClusterIP = ""
    59			service.Spec.ClusterIPs = nil
    60		}
    61	
    62		/* Do not delete NodePorts if restore triggered with "--preserve-nodeports" flag */
    63		if boolptr.IsSetToTrue(input.Restore.Spec.PreserveNodePorts) {
    64			a.log.Info("Restoring Services with original NodePort(s)")
    65		} else {
    66			if err := deleteNodePorts(service); err != nil {
    67				return nil, err
    68			}
    69			if err := deleteHealthCheckNodePort(service); err != nil {
    70				return nil, err
    71			}
    72		}
    73	
    74		res, err := runtime.DefaultUnstructuredConverter.ToUnstructured(service)
    75		if err != nil {
    76			return nil, errors.WithStack(err)
    77		}
    78	
    79		return velero.NewRestoreItemActionExecuteOutput(&unstructured.Unstructured{Object: res}), nil
    80	}
